-- PDB에 접속한 상태에서
ALTER SYSTEM SET open_cursors = 500 SCOPE=BOTH;
ALTER SYSTEM SET cursor_sharing = 'FORCE' SCOPE=BOTH;

-- 변경 확인
SHOW PARAMETER open_cursors;
SHOW PARAMETER cursor_sharing;

-- CDB 기본값으로 복원
ALTER SYSTEM RESET open_cursors SCOPE=BOTH;

-- CDB$ROOT에서 실행
-- Lockdown Profile 생성
CREATE LOCKDOWN PROFILE secure_pdb_profile;

-- ALTER SYSTEM 문 제한
ALTER LOCKDOWN PROFILE secure_pdb_profile
  DISABLE STATEMENT = ('ALTER SYSTEM')
  CLAUSE = ('SET')
  OPTION ALL EXCEPT = ('cursor_sharing', 'optimizer_mode');

-- 네트워크 접근 제한
ALTER LOCKDOWN PROFILE secure_pdb_profile
  DISABLE FEATURE = ('UTL_HTTP', 'UTL_TCP', 'UTL_SMTP');

-- PDB에 Lockdown Profile 할당
ALTER SESSION SET CONTAINER = pdb1;
ALTER SYSTEM SET pdb_lockdown = 'SECURE_PDB_PROFILE' SCOPE=BOTH;

-- 콜드 클론: 소스 PDB를 READ ONLY로 변경 후 클론
ALTER PLUGGABLE DATABASE pdb_src CLOSE IMMEDIATE;
ALTER PLUGGABLE DATABASE pdb_src OPEN READ ONLY;

CREATE PLUGGABLE DATABASE pdb_clone FROM pdb_src
  FILE_NAME_CONVERT = ('/oradata/CDB1/pdb_src/', '/oradata/CDB1/pdb_clone/');

ALTER PLUGGABLE DATABASE pdb_clone OPEN;

-- 핫 클론 (12.2+): 소스 PDB가 READ WRITE 상태에서 클론
CREATE PLUGGABLE DATABASE pdb_hot_clone FROM pdb_src
  FILE_NAME_CONVERT = ('/oradata/CDB1/pdb_src/', '/oradata/CDB1/pdb_hot_clone/');

-- 소스 CDB에서 공통 사용자 생성 및 권한 부여
-- (소스 CDB에서 실행)
CREATE USER c##clone_user IDENTIFIED BY clone_pass CONTAINER=ALL;
GRANT CREATE SESSION, CREATE PLUGGABLE DATABASE TO c##clone_user CONTAINER=ALL;

-- 대상 CDB에서 DB Link 생성
-- (대상 CDB에서 실행)
CREATE DATABASE LINK remote_cdb_link
  CONNECT TO c##clone_user IDENTIFIED BY clone_pass
  USING '(DESCRIPTION=(ADDRESS=(PROTOCOL=TCP)(HOST=source_host)(PORT=1521))(CONNECT_DATA=(SERVICE_NAME=CDB1)))';

-- 대상 CDB에서 원격 클론 실행
CREATE PLUGGABLE DATABASE pdb_remote_clone FROM pdb_src@remote_cdb_link
  FILE_NAME_CONVERT = ('/oradata/CDB_SRC/pdb_src/', '/oradata/CDB_DST/pdb_remote_clone/');

-- 새 PDB 열기
ALTER PLUGGABLE DATABASE pdb_remote_clone OPEN;

-- PDB 상태 확인
SELECT pdb_name, status, con_id FROM cdb_pdbs WHERE pdb_name = 'PDB_REMOTE_CLONE';

-- 자동 새로고침 (10분 간격)
CREATE PLUGGABLE DATABASE pdb_refresh_auto FROM pdb_src@remote_cdb_link
  FILE_NAME_CONVERT = ('/oradata/CDB_SRC/pdb_src/', '/oradata/CDB_DST/pdb_refresh_auto/')
  REFRESH MODE EVERY 10 MINUTES;

-- 수동 새로고침
CREATE PLUGGABLE DATABASE pdb_refresh_manual FROM pdb_src@remote_cdb_link
  FILE_NAME_CONVERT = ('/oradata/CDB_SRC/pdb_src/', '/oradata/CDB_DST/pdb_refresh_manual/')
  REFRESH MODE MANUAL;

-- Refreshable Clone PDB 열기 (READ ONLY만 가능)
ALTER PLUGGABLE DATABASE pdb_refresh_auto OPEN READ ONLY;

-- 수동 새로고침 실행
ALTER PLUGGABLE DATABASE pdb_refresh_manual CLOSE;
ALTER PLUGGABLE DATABASE pdb_refresh_manual REFRESH;
ALTER PLUGGABLE DATABASE pdb_refresh_manual OPEN READ ONLY;

-- 새로고침 간격 변경 (수동 → 자동 5분)
ALTER PLUGGABLE DATABASE pdb_refresh_manual
  REFRESH MODE EVERY 5 MINUTES;

-- 새로고침 비활성화 (일반 PDB로 전환)
ALTER PLUGGABLE DATABASE pdb_refresh_manual CLOSE;
ALTER PLUGGABLE DATABASE pdb_refresh_manual
  REFRESH MODE NONE;
ALTER PLUGGABLE DATABASE pdb_refresh_manual OPEN;

-- SWITCHOVER 전 최종 동기화
ALTER PLUGGABLE DATABASE pdb_refresh_auto CLOSE;
ALTER PLUGGABLE DATABASE pdb_refresh_auto REFRESH;

-- SWITCHOVER 실행 (역할 전환)
ALTER PLUGGABLE DATABASE pdb_refresh_auto
  REFRESH MODE SWITCHOVER;

-- SWITCHOVER 후 새로운 소스 PDB로 OPEN
ALTER PLUGGABLE DATABASE pdb_refresh_auto OPEN;

-- Snapshot Copy PDB 생성 (ACFS 환경)
CREATE PLUGGABLE DATABASE pdb_snap FROM pdb_src
  SNAPSHOT COPY;

ALTER PLUGGABLE DATABASE pdb_snap OPEN;

-- Snapshot Copy PDB 확인
SELECT pdb_name, status, snapshot_parent_con_id
FROM cdb_pdbs
WHERE pdb_name = 'PDB_SNAP';
